def process_streaming_response(stream):
    thinking_content = ""
    text_content = ""
    thinking_tokens = 0

    for event in stream:
        if event.type == "content_block_delta":
            if hasattr(event.delta, "thinking"):
                thinking_content += event.delta.thinking
                print(event.delta.thinking, end="", flush=True)
            elif hasattr(event.delta, "text"):
                text_content += event.delta.text
                print(event.delta.text, end="", flush=True)

        elif event.type == "message_delta":
            thinking_tokens = event.usage.output_tokens_details.thinking_tokens

    return {
        "thinking": thinking_content,
        "response": text_content,
        "thinking_tokens": thinking_tokens
    }

// Display thinking in collapsible UI
function streamThinkingToUI(stream) {
    const thinkingDiv = document.getElementById('thinking');
    const responseDiv = document.getElementById('response');

    stream.on('content_block_start', (block) => {
        if (block.type === 'thinking') {
            thinkingDiv.classList.add('show'); // Expand thinking
            thinkingDiv.textContent = '';
        } else {
            responseDiv.textContent = '';
        }
    });

    stream.on('content_block_delta', (delta) => {
        if (delta.type === 'thinking_delta') {
            thinkingDiv.textContent += delta.thinking;
        } else if (delta.type === 'text_delta') {
            responseDiv.textContent += delta.text;
        }
    });
}
